var Base = require('../temp/base');

var App = function(){};
Base._extend(App, {
  initEvents : function(){
    var _self = this;
    this.events = {
      'fnmenu' : {
        'menuselected' : function(opt){
          _self.updateRouter(opt, true);
        }
      }
    };
  }
});
exports = module.exports = App;